// === CF Gate Decision (T7a) : webhook Telegram/Studio -> POST /productions/{id}/gate ===
// Signale une decision de gate humaine au ContentWorkflow Temporal via cf-api.
// Route REST NATIVE (pas /compat/*) : auth = Authorization Bearer CF_API_TOKEN,
// PAS x-webhook-secret (ce secret protege uniquement l'entree du webhook n8n,
// comme sur cf-update-content/cf-create-content/cf-read-content).
const data = $input.first().json;
const body = data.body || data;

// Validation du secret webhook entrant (meme pattern que cf-update-content) :
// header x-webhook-secret, repli body.secret.
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');
const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
const gate = body.gate;
const decision = body.decision || 'approve';
const note = body.note || '';
const author = body.author || '';

// Garde-fous lisibles AVANT l'appel reseau : content_id/gate manquants ->
// reponse d'erreur structuree, jamais un throw (pas de 500 opaque), et on
// evite de construire une URL avec 'undefined' dans le chemin.
if (!content_id) {
  return [{ json: { ok: false, statusCode: 422, error: 'Missing required field: content_id' } }];
}
if (!gate) {
  return [{ json: { ok: false, statusCode: 422, error: 'Missing required field: gate' } }];
}

// content_id = UUID (domaine v2, cutover C) : jamais parseInt, interpolation brute.
function cfApiPost(urlStr, payload, token) {
  return new Promise((resolve) => {
    const lib = urlStr.startsWith('https') ? require('https') : require('http');
    const bodyStr = JSON.stringify(payload || {});
    const hdrs = {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(bodyStr),
      'Authorization': `Bearer ${token}`
    };
    const req = lib.request(urlStr, { method: 'POST', headers: hdrs }, (res) => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => {
        let parsed;
        try { parsed = JSON.parse(d); } catch (e) { parsed = d; }
        // Relai NON-2xx SANS throw : reponse lisible pour l'appelant (bot Telegram /
        // skill OpenClaw) avec statusCode + corps d'erreur renvoye par cf-api.
        // Couvre au minimum : 404 (production inconnue), 422 (gate/decision hors
        // enum, cf. GateIn Literal), 502 (signal Temporal echoue : workflow clos
        // ou reseau), 503 (Temporal non configure).
        if (res.statusCode < 200 || res.statusCode >= 300) {
          resolve({ ok: false, statusCode: res.statusCode, error: parsed });
        } else {
          const extra = (typeof parsed === 'object' && parsed !== null) ? parsed : { body: parsed };
          resolve({ ok: true, statusCode: res.statusCode, ...extra });
        }
      });
    });
    req.on('error', (err) => {
      // Panne reseau (cf-api injoignable) : meme forme de reponse lisible que les
      // erreurs HTTP -- jamais de reject/throw ici non plus.
      resolve({ ok: false, statusCode: 0, error: `network error: ${err.message}` });
    });
    req.write(bodyStr); req.end();
  });
}

const apiBase = $env.CF_API_BASE_URL || 'http://cf-api:8000';
const token = $env.CF_API_TOKEN || '';
const resp = await cfApiPost(`${apiBase}/productions/${content_id}/gate`, { gate, decision, note, author }, token);
return [{ json: resp }];
